impl.spec_text:
use vstd::set::*;
use vstd::map::*;

proof fn test_map() {
    let s1 = Set::<int>::empty().insert(1).insert(2).insert(3);
    let m1 = s1.mk_map(|k: int| 10 * k);
    let m3: Map<int, int> = m1;
    let m4: Map<nat, int> = m1; // FAILS: see https://github.com/FStarLang/FStar/issues/1542
}

